{"new_string":"    private fun checkForAnnotationToBePlacedOnSeparateLine(
        node: ASTNode,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        autoCorrect: Boolean,
    ) {
        val isFollowedWithAnnotationHavingValueArgumentList =
            node
                .siblings(forward = true)
                .any { it.isAnnotationEntryWithValueArgumentList() }
        val isPrecededWithAnnotationOnOtherLine =
            node
                .siblings(forward = false)
                .any { it.isWhiteSpaceWithNewline() }
        val isPrecededByArrayAnnotationOnSameLine =
            node
                .siblings(forward = false)
                .takeWhile { !it.isWhiteSpaceWithNewline() }
                .any { it.elementType == ANNOTATION }
        if (isFollowedWithAnnotationHavingValueArgumentList || isPrecededWithAnnotationOnOtherLine || isPrecededByArrayAnnotationOnSameLine) {
            emit(
                node.startOffset,
                "Annotation must be placed on separate line",
                true,
            )
            if (autoCorrect) {
                node
                    .lastChildLeafOrSelf()
                    .nextLeaf()
                    ?.upsertWhitespaceBeforeMe(getNewlineWithIndent(node.treeParent))
            }
        }
    }

